import (
    usagebasedrating "github.com/openmeterio/openmeter/openmeter/billing/charges/usagebased/service/rating"
    billingrating "github.com/openmeterio/openmeter/openmeter/billing/rating"
    "github.com/openmeterio/openmeter/openmeter/streaming"
)

svc, err := usagebasedrating.New(usagebasedrating.Config{
    StreamingConnector: streamingConnector,
    RatingService:      ratingService,
})
if err != nil { return err }

result, err := svc.GetDetailedLinesForUsage(ctx, usagebasedrating.GetDetailedLinesForUsageInput{
    Charge:          charge,
    PriorRuns:       charge.Realizations, // must have DetailedLines expanded
    Customer:        customerOverride,
    FeatureMeter:    featureMeter,
    StoredAtOffset:  asOf,
    IgnoreMinimumCommitment: false,
})
// result.DetailedLines[i].ChildUniqueReferenceID is already period-scoped
// result.Quantity is the raw metered value used for the rating

import (
    "github.com/openmeterio/openmeter/openmeter/billing/charges/usagebased/service/run"
    usagebasedrating "github.com/openmeterio/openmeter/openmeter/billing/charges/usagebased/service/rating"
)

runSvc, err := run.New(run.Config{
    Adapter: usagebasedAdapter,
    Rater:   ratingService,
    Handler: usagebasedHandler,
    Lineage: lineageService,
})
if err != nil { return err }

result, err := runSvc.CreateRatedRun(ctx, run.CreateRatedRunInput{
    Charge:                  charge,
    CustomerOverride:        customerOverride,
    FeatureMeter:            featureMeter,
    Type:                    usagebased.RealizationRunTypeFinalRealization,
    AsOf:                    now,
    CollectionEnd:           collectionEnd,
    LineID:                  &lineID,
    IgnoreMinimumCommitment: false,
    CreditAllocation:        run.CreditAllocationExact,
    CurrencyCalculator:      currencyCalc,
})
// result.Charge has updated State.CurrentRealizationRunID
// result.Run has DetailedLines and CreditsAllocated populated
